<template>
  <div class="container">
    <div class="row">
      <div class="col-md-12">
        <div class="mt-4 mb-4">
          <h1><strong class="courier">scoreboard()</strong></h1>
          <em class="monaco">fast and more.</em>
        </div>
        <div class="card text-white text-left mb-5">
          <div class="maskot">
            <img src="~@/assets/img/maskot.png" class="maskot-img" />
          </div>
          <div class="card-body">
            <!-- <button @click="urutkan" class="btn btn-danger text-white mt-5 mb-3">Urutkan</button> -->
            <div class="table-responsive pt-5">
              <p v-if="tim.length > 0" class="monaco">
                there are {{ tim.length }} teams.
              </p>
              <p v-else>there is no team.</p>
              <table class="table table-striped text-white">
                <thead>
                  <tr>
                    <th>TEAM</th>
                    <th>CLASS</th>
                    <th>TIME</th>
                    <th>CASE</th>
                    <!-- <th>ACTION</th> -->
                  </tr>
                </thead>
                <tbody class="monaco">
                  <tr v-for="t in tim" :key="t.id" id="data">
                    <td>{{ t.nama }}</td>
                    <td>{{ t.kelas }}</td>
                    <td>{{ t.waktu }}</td>
                    <td>{{ t.case }}</td>
                    <!-- <td><button @click="removeTim(t.id)">R</button></td> -->
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>

        <div v-if="user" class="card text-white text-left mb-5">
          <div class="card-body monaco">
            <div class="row">
              <div class="col-md-6">
                <h4 class="mb-3">
                  Add Manual
                  <button @click="signOut" v-if="user" class="btn btn-danger">Sign Out</button>
                </h4>
                <form @submit.prevent="addTim">
                  <div class="form-group">
                    <input
                      type="text"
                      id="inputNama"
                      v-model="inputNama"
                      class="form-control form-control-lg"
                      placeholder="- Nama Tim -"
                      autofocus
                      autocomplete="off"
                    />
                  </div>
                  <div class="form-group">
                    <select v-model="inputKelas" class="form-control form-control-lg">
                      <option value="">- Kelas -</option>
                      <option v-for="k in kelas" :key="k" :value="k">
                        {{ k }}
                      </option>
                    </select>
                  </div>
                  <div class="form-group">
                    <input
                      type="text"
                      v-model="inputWaktu"
                      class="form-control form-control-lg"
                      placeholder="- Waktu -"
                    />
                  </div>
                  <div class="form-group">
                    <select v-model="inputCase" class="form-control form-control-lg">
                      <option value="">- Case -</option>
                      <option value="1">Case-1</option>
                      <option value="2">Case-2</option>
                    </select>
                  </div>
                  <button
                    v-if="inputNama.length > 0 && inputKelas.length > 0 && inputWaktu.length > 0 && inputCase.length >0"
                    class="btn btn-green btn-lg text-white">
                    save()
                  </button>
                </form>
              </div>
              <div class="col-md-6">
                <!-- belum ada isinya -->
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      inputNama: "",
      inputKelas: "",
      inputWaktu: "",
      inputCase: "",
      kelas: ["XII.RPL-1", "XII.RPL-2", "XII.RPL-3", "XII.RPL-4"],
      tim: [],
      user: this.$supabase.auth.user(),
    };
  },
  async mounted() {
    await this.getData();
  },

  created() {
    this.subsData()
  },

  methods: {
    async signOut() {
      const { error } = await this.$supabase.auth.signOut()
      if(error) {
        console.log(error)
      }
      this.$router.push('/')
    },
    async getData() {
      const { data, error } = await this.$supabase
        .from('score')
        .select('*')
        .order('created_at')
      
      if(error) {
        console.error(error);
        return
      }

      this.setData(data)
    },

    setData(data) {
      this.tim = data; 
    },

    async addTim() {
      if (this.inputNama != "") {
        const { data, err } = await this.$supabase
          .from('score')
          .insert(
            {
              nama: this.inputNama,
              kelas: this.inputKelas,
              waktu: this.inputWaktu,
              case: this.inputCase,
            }
          )

        if(err) {
          console.error(err)
          return
        }

        // this.tim.push(currTim);
        this.inputNama = "";
        this.inputKelas = "";
        this.inputWaktu = "";
        this.inputCase = "";
        document.getElementById("inputNama").focus();
      }
    },

    subsData() {
      const mySubscription = this.$supabase
        .from('score')
        .on('INSERT', (data) => {
          if(data.new) {
            this.tim.push(data.new)
          }
        })
        .subscribe()
    },

    async removeTim(id) {
      if (confirm('Hapus ini?')) {
        const { data, err } = await this.$supabase
          .from('score')
          .delete()
          .match({ id: id })
      }
    }
  },
};
</script>

<style scoped>
.form-control {
  border: none;
  border-radius: 25px;
}
.form-group {
  margin-bottom: 1.2em;
}
</style>
